local function parseList(s)local t={}if s==""then return t end for w in s:gmatch("%S+")do table.insert(t,w:lower())end return t end
local function matchAny(arr,n)local ln=n:lower()for _,k in ipairs(arr)do if ln:find(k,1,true)then return true end end return false end
local function isFriend(n)if isImm(n)then return true end return matchAny(LH.friendList,n)end
local function isTarget(n)if isImm(n)then return false end if #LH.targetList==0 then return true end return matchAny(LH.targetList,n)end
local function findPlayer(n)if n==""then return nil end local s=n:lower()for _,p in ipairs(Players:GetPlayers())do if p~=lp and(p.Name:lower():find(s)or(p.DisplayName and p.DisplayName:lower():find(s)))then if not isImm(p.Name)then return p end end end return nil end
local function findNearest(r)local ch=lp.Character if not ch then return nil end local hrp=ch:FindFirstChild("HumanoidRootPart")if not hrp then return nil end local mp=hrp.Position local best,bd=nil,r for _,p in ipairs(Players:GetPlayers())do if p==lp or not p.Character then continue end if isImm(p.Name)or isFriend(p.Name)or isFriend(p.DisplayName)then continue end if not isTarget(p.Name)and not isTarget(p.DisplayName)then continue end local h=p.Character:FindFirstChild("HumanoidRootPart")local hu=p.Character:FindFirstChildOfClass("Humanoid")if h and hu and hu.Health>0 then local d=(h.Position-mp).Magnitude if d<=r and d<bd then bd=d;best=p end end end return best end
