local function findRemotes()local function searchPath(...)local cur=ReplicatedStorage for _,n in ipairs({...})do if cur then cur=cur:FindFirstChild(n)else return nil end end return cur end HitRF=searchPath("Packages","Knit","Services","CombatService","RF","Hit")PunchRF=searchPath("Packages","Knit","Services","CombatService","RF","PunchDo")BlockRF=searchPath("Packages","Knit","Services","CombatService","RF","Block")GrabRF=searchPath("Packages","Knit","Services","CombatService","RF","Grab")if not HitRF then local function scan(obj,name)for _,child in ipairs(obj:GetChildren())do if child:IsA("RemoteFunction")or child:IsA("RemoteEvent")then if child.Name:lower()==name then return child end end local found=scan(child,name)if found then return found end end end HitRF=scan(ReplicatedStorage,"hit")or scan(ReplicatedStorage,"punch")GrabRF=scan(ReplicatedStorage,"grab")end local rem=ReplicatedStorage:FindFirstChild("Remotes")if rem then BioR=rem:FindFirstChild("UpdateBio")BioColR=rem:FindFirstChild("UpdateBioColor")RPColR=rem:FindFirstChild("UpdateRPColor")NameR=rem:FindFirstChild("UpdateRPName")end end findRemotes()
local function clickOnTarget(targetChar)if not targetChar or not targetChar.Parent then return end local head=targetChar:FindFirstChild("Head")if head then mouse.Move(head.Position)task.wait(0.01)mouse.Button1Down:Fire()task.wait(0.01)mouse.Button1Up:Fire()end end
local function doHit(hum,myhrp,targetChar)if not hum or not hum.Parent then return end if hum.Parent and hum.Parent.Name and isImm(hum.Parent.Name)then return end if HitRF then local pos=myhrp.Position if LH.BypassRange then local hrp=hum.Parent:FindFirstChild("HumanoidRootPart")if hrp then pos=hrp.Position+hrp.CFrame.LookVector*2 end end pcall(function()if HitRF:IsA("RemoteFunction")then HitRF:InvokeServer(hum,vector.create(pos.X,pos.Y,pos.Z))elseif HitRF:IsA("RemoteEvent")then HitRF:FireServer(hum,vector.create(pos.X,pos.Y,pos.Z))end end)else clickOnTarget(hum.Parent)end end
local function doGrab(target)if not target or not target.Character or isImm(target.Name)then return end if GrabRF then pcall(function()if GrabRF:IsA("RemoteFunction")then GrabRF:InvokeServer(target)elseif GrabRF:IsA("RemoteEvent")then GrabRF:FireServer(target)end end)else clickOnTarget(target.Character)end end
local function doRawGrab(target)if not target or not target.Character or isImm(target.Name)then return end if GrabRF then pcall(function()if GrabRF:IsA("RemoteFunction")then GrabRF:InvokeServer(target)elseif GrabRF:IsA("RemoteEvent")then GrabRF:FireServer(target)end end)else clickOnTarget(target.Character)end end
local function cleanRag(ch)if not ch then return end local hu=ch:FindFirstChildOfClass("Humanoid")if hu then for _,st in ipairs({Enum.HumanoidStateType.Ragdoll,Enum.HumanoidStateType.Physics,Enum.HumanoidStateType.FallingDown,Enum.HumanoidStateType.PlatformStanding})do pcall(function()hu:SetStateEnabled(st,false)end)end hu.PlatformStand=false end for _,o in ipairs(ch:GetDescendants())do if(o:IsA("BaseConstraint")or o:IsA("Attachment"))and o.Name:lower():find("ragdoll")then o:Destroy()elseif o:IsA("Motor6D")then o.Enabled=true end end end
local kaConn,kaLast=nil,0
local function StartKA()if kaConn then kaConn:Disconnect();kaConn=nil end if not LH.KillAura then return end kaConn=RunService.Heartbeat:Connect(function()if not LH.KillAura then return end local ch=lp.Character local myhrp=ch and ch:FindFirstChild("HumanoidRootPart")if not myhrp then return end local now=tick()local interval=1/math.clamp(LH.AttacksPerSecond,1,99999)if now-kaLast<interval then return end local targets={}for _,p in ipairs(Players:GetPlayers())do if p==lp or not p.Character then continue end if isImm(p.Name)or isFriend(p.Name)or isFriend(p.DisplayName)then continue end if not isTarget(p.Name)and not isTarget(p.DisplayName)then continue end local h=p.Character:FindFirstChild("HumanoidRootPart")local hu=p.Character:FindFirstChildOfClass("Humanoid")if h and hu and hu.Health>0 then local d=(h.Position-myhrp.Position).Magnitude if d<=LH.KillAuraRange then table.insert(targets,{hu=hu,char=p.Character,dist=d})end end end if #targets==0 then return end if LH.KillAuraStyle==1 then table.sort(targets,function(a,b)return a.dist<b.dist end)local t=targets[1]task.spawn(function()doHit(t.hu,myhrp,t.char)end)elseif LH.KillAuraStyle==2 then for _,t in ipairs(targets)do task.spawn(function()doHit(t.hu,myhrp,t.char)end)end else for _,t in ipairs(targets)do task.spawn(function()doHit(t.hu,myhrp,t.char)end)end for i=1,math.min(3,#targets)do task.spawn(function()local t=targets[i]if t then doHit(t.hu,myhrp,t.char)end end)end end kaLast=now end)end
local function StopKA()if kaConn then kaConn:Disconnect();kaConn=nil end kaLast=0 end
