RunService.Heartbeat:Connect(function()if not LH.AutoStomp then return end local ch=lp.Character local hrp=ch and ch:FindFirstChild("HumanoidRootPart")if not hrp then return end for _,p in ipairs(Players:GetPlayers())do if p~=lp and p.Character and not isFriend(p.Name)and not isImm(p.Name)then local thu=p.Character:FindFirstChildOfClass("Humanoid")local th=p.Character:FindFirstChild("HumanoidRootPart")if thu and th and thu.Health>0 and(thu.PlatformStand or thu.Sit)then task.spawn(function()local orig=hrp.CFrame hrp.CFrame=th.CFrame*CFrame.new(0,0,-2)doHit(thu,hrp,p.Character)task.wait(0.05)if hrp and hrp.Parent then hrp.CFrame=orig end end)end end end end)
RunService.Heartbeat:Connect(function(dt)local ch=lp.Character if not ch then return end local hrp=ch:FindFirstChild("HumanoidRootPart")if not hrp then return end if LH.Strafe and LH.strafeName~=""then local tgt=findPlayer(LH.strafeName)if tgt and tgt.Character then local th=tgt.Character:FindFirstChild("HumanoidRootPart")if th then local tp=th.Position local np if LH.Backstab then np=tp+(-th.CFrame.LookVector*LH.StrafeRadius)+Vector3.new(0,LH.StrafeOffset,0)else LH.strafeAngle=LH.strafeAngle+LH.StrafeSpeed*dt np=Vector3.new(tp.X+math.cos(LH.strafeAngle)*LH.StrafeRadius,tp.Y+LH.StrafeOffset,tp.Z+math.sin(LH.strafeAngle)*LH.StrafeRadius)end hrp.CFrame=CFrame.new(np,Vector3.new(tp.X,hrp.Position.Y,tp.Z))end end end if LH.Orbit and LH.orbitName~=""then local tgt=findPlayer(LH.orbitName)if tgt and tgt.Character then local th=tgt.Character:FindFirstChild("HumanoidRootPart")if th then LH.orbitAngle=LH.orbitAngle+LH.orbSpeed*dt local tp=th.Position hrp.CFrame=CFrame.new(tp+Vector3.new(math.cos(LH.orbitAngle)*LH.orbRadius,LH.orbHeight,math.sin(LH.orbitAngle)*LH.orbRadius),tp)hrp.AssemblyLinearVelocity=Vector3.zero end end end if LH.HeadSit and LH.headSitName~=""then local tgt=findPlayer(LH.headSitName)if tgt and tgt.Character then local hd=tgt.Character:FindFirstChild("Head")if hd and(hd.Position-hrp.Position).Magnitude<=LH.KillAuraRange*2 then hrp.CFrame=CFrame.new(hd.Position+Vector3.new(0,3,0))end end end end)
